function evaluateReversePolishNotation(data) {
    const stack = [];
    const tokens = data.split(' ');
    for (const token of tokens) {
        if (!isNaN(token)) {
            stack.push(Number(token));
        } else {
            const b = stack.pop();
            const a = stack.pop();
            let result;
            switch (token) {
                case '+':
                    result = a + b;
                    break;
                case '-':
                    result = a - b;
                    break;
                case '*':
                    result = a * b;
                    break;
                case '/':
                    result = Math.trunc(a / b); // Use truncation for integer division
                    break;
            }
            stack.push(result);
        }
    }
    return stack[0];
}

