#include <vector>
#include <string>
#include <stack>
#include <cstdlib>
using namespace std;
class Solution {
    public:
    int evaluateReversePolishNotation(vector<string>& data) {
        stack<int> stk;
        for (const string& token : data) {
            if (isdigit(token[0]) || (token.size() > 1 && token[0] == '-')) {
                stk.push(stoi(token));
            }
            else {
                int b = stk.top(); stk.pop();
                int a = stk.top(); stk.pop();
                if (token == "+") {
                    stk.push(a + b);
                }
                else if (token == "-") {
                    stk.push(a - b);
                }
                else if (token == "*") {
                    stk.push(a * b);
                }
                else if (token == "/") {
                    stk.push(a / b);
                }
            }
        }
        return stk.top();
    }
}
