public class Solution {
    public int evaluateReversePolishNotation(string[] data) {
        Stack<int> stack = new Stack<int>();
        foreach (string token in data) {
            if (int.TryParse(token, out int num)) {
                stack.Push(num);
            } else {
                int b = stack.Pop();
                int a = stack.Pop();
                switch (token) {
                    case "+":
                        stack.Push(a + b);
                        break;
                    case "-":
                        stack.Push(a - b);
                        break;
                    case "*":
                        stack.Push(a * b);
                        break;
                    case "/":
                        stack.Push(a / b);
                        break;
                }
            }
        }
        return stack.Pop();
    }
